/**
 * Base Repository Interface
 * Provides common CRUD operations for all repositories
 */
export interface BaseRepository<T, CreateDto, UpdateDto> {
  findAll(filters?: Record<string, any>): Promise<T[]>
  findById(id: string): Promise<T | null>
  create(data: CreateDto): Promise<T>
  update(id: string, data: UpdateDto): Promise<T>
  delete(id: string): Promise<void>
}

/**
 * Pagination options for list queries
 */
export interface PaginationOptions {
  page?: number
  limit?: number
  sortBy?: string
  sortOrder?: 'asc' | 'desc'
}

/**
 * Paginated response wrapper
 */
export interface PaginatedResponse<T> {
  data: T[]
  pagination: {
    page: number
    limit: number
    total: number
    totalPages: number
  }
}

import { PrismaClient, User, UserRole, PremiumTier } from '@prisma/client'
import { BaseRepository, PaginatedResponse, PaginationOptions } from './base.repository'

/**
 * User creation DTO
 */
export interface CreateUserDto {
  email: string
  username: string
  passwordHash: string
  role?: UserRole
  discordId?: string
  googleId?: string
}

/**
 * User update DTO
 */
export interface UpdateUserDto {
  email?: string
  username?: string
  passwordHash?: string
  role?: UserRole
  premiumTier?: PremiumTier
  premiumExpiry?: Date
  goldBalance?: bigint
  isVerified?: boolean
}

/**
 * User filter options
 */
export interface UserFilters {
  role?: UserRole
  isVerified?: boolean
  premiumTier?: PremiumTier
  search?: string
}

/**
 * User Repository Interface
 */
export interface UserRepository extends BaseRepository<User, CreateUserDto, UpdateUserDto> {
  findByEmail(email: string): Promise<User | null>
  findByUsername(username: string): Promise<User | null>
  findByDiscordId(discordId: string): Promise<User | null>
  findByGoogleId(googleId: string): Promise<User | null>
  findAllPaginated(filters?: UserFilters, options?: PaginationOptions): Promise<PaginatedResponse<User>>
  incrementLoginAttempts(id: string): Promise<void>
  resetLoginAttempts(id: string): Promise<void>
  lockAccount(id: string, until: Date): Promise<void>
}

/**
 * Prisma implementation of User Repository
 * Follows Repository Pattern from Universal Brain backend-patterns
 */
export class PrismaUserRepository implements UserRepository {
  constructor(private prisma: PrismaClient) {}

  async findAll(filters?: UserFilters): Promise<User[]> {
    const where: any = {}

    if (filters?.role) {
      where.role = filters.role
    }

    if (filters?.isVerified !== undefined) {
      where.isVerified = filters.isVerified
    }

    if (filters?.premiumTier) {
      where.premiumTier = filters.premiumTier
    }

    if (filters?.search) {
      where.OR = [
        { email: { contains: filters.search, mode: 'insensitive' } },
        { username: { contains: filters.search, mode: 'insensitive' } }
      ]
    }

    return this.prisma.user.findMany({
      where,
      orderBy: { createdAt: 'desc' }
    })
  }

  async findAllPaginated(
    filters?: UserFilters,
    options?: PaginationOptions
  ): Promise<PaginatedResponse<User>> {
    const page = options?.page || 1
    const limit = options?.limit || 10
    const skip = (page - 1) * limit

    const where: any = {}

    if (filters?.role) {
      where.role = filters.role
    }

    if (filters?.isVerified !== undefined) {
      where.isVerified = filters.isVerified
    }

    if (filters?.premiumTier) {
      where.premiumTier = filters.premiumTier
    }

    if (filters?.search) {
      where.OR = [
        { email: { contains: filters.search, mode: 'insensitive' } },
        { username: { contains: filters.search, mode: 'insensitive' } }
      ]
    }

    const [data, total] = await Promise.all([
      this.prisma.user.findMany({
        where,
        skip,
        take: limit,
        orderBy: options?.sortBy
          ? { [options.sortBy]: options.sortOrder || 'asc' }
          : { createdAt: 'desc' }
      }),
      this.prisma.user.count({ where })
    ])

    return {
      data,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit)
      }
    }
  }

  async findById(id: string): Promise<User | null> {
    return this.prisma.user.findUnique({
      where: { id }
    })
  }

  async findByEmail(email: string): Promise<User | null> {
    return this.prisma.user.findUnique({
      where: { email }
    })
  }

  async findByUsername(username: string): Promise<User | null> {
    return this.prisma.user.findUnique({
      where: { username }
    })
  }

  async findByDiscordId(discordId: string): Promise<User | null> {
    return this.prisma.user.findUnique({
      where: { discordId }
    })
  }

  async findByGoogleId(googleId: string): Promise<User | null> {
    return this.prisma.user.findUnique({
      where: { googleId }
    })
  }

  async create(data: CreateUserDto): Promise<User> {
    return this.prisma.user.create({
      data: {
        email: data.email,
        username: data.username,
        passwordHash: data.passwordHash,
        role: data.role || 'PLAYER',
        discordId: data.discordId,
        googleId: data.googleId
      }
    })
  }

  async update(id: string, data: UpdateUserDto): Promise<User> {
    return this.prisma.user.update({
      where: { id },
      data
    })
  }

  async delete(id: string): Promise<void> {
    await this.prisma.user.update({
      where: { id },
      data: { deletedAt: new Date() }
    })
  }

  async incrementLoginAttempts(id: string): Promise<void> {
    await this.prisma.user.update({
      where: { id },
      data: {
        loginAttempts: { increment: 1 }
      }
    })
  }

  async resetLoginAttempts(id: string): Promise<void> {
    await this.prisma.user.update({
      where: { id },
      data: {
        loginAttempts: 0,
        lockedUntil: null
      }
    })
  }

  async lockAccount(id: string, until: Date): Promise<void> {
    await this.prisma.user.update({
      where: { id },
      data: {
        lockedUntil: until
      }
    })
  }
}

/**
 * Base API Error class
 * Following error handling patterns from Universal Brain backend-patterns
 */
export class ApiError extends Error {
  constructor(
    public statusCode: number,
    public message: string,
    public isOperational = true,
    public details?: any
  ) {
    super(message)
    this.name = this.constructor.name
    Object.setPrototypeOf(this, ApiError.prototype)
    Error.captureStackTrace(this, this.constructor)
  }
}

/**
 * 400 Bad Request
 */
export class BadRequestError extends ApiError {
  constructor(message: string = 'Bad request', details?: any) {
    super(400, message, true, details)
  }
}

/**
 * 401 Unauthorized
 */
export class UnauthorizedError extends ApiError {
  constructor(message: string = 'Unauthorized') {
    super(401, message, true)
  }
}

/**
 * 403 Forbidden
 */
export class ForbiddenError extends ApiError {
  constructor(message: string = 'Forbidden') {
    super(403, message, true)
  }
}

/**
 * 404 Not Found
 */
export class NotFoundError extends ApiError {
  constructor(resource: string = 'Resource') {
    super(404, `${resource} not found`, true)
  }
}

/**
 * 409 Conflict
 */
export class ConflictError extends ApiError {
  constructor(message: string = 'Resource already exists') {
    super(409, message, true)
  }
}

/**
 * 422 Unprocessable Entity
 */
export class ValidationError extends ApiError {
  constructor(message: string = 'Validation failed', details?: any) {
    super(422, message, true, details)
  }
}

/**
 * 429 Too Many Requests
 */
export class RateLimitError extends ApiError {
  constructor(message: string = 'Too many requests') {
    super(429, message, true)
  }
}

/**
 * 500 Internal Server Error
 */
export class InternalServerError extends ApiError {
  constructor(message: string = 'Internal server error') {
    super(500, message, false)
  }
}

/**
 * 503 Service Unavailable
 */
export class ServiceUnavailableError extends ApiError {
  constructor(message: string = 'Service temporarily unavailable') {
    super(503, message, true)
  }
}

import { ExceptionFilter, Catch, ArgumentsHost, HttpException, HttpStatus } from '@nestjs/common'
import { Request, Response } from 'express'
import { ApiError } from '../errors/api-error'
import { ZodError } from 'zod'

/**
 * Global exception filter
 * Handles all errors and formats them consistently
 * Following Universal Brain backend-patterns error handling
 */
@Catch()
export class GlobalExceptionFilter implements ExceptionFilter {
  catch(exception: unknown, host: ArgumentsHost) {
    const ctx = host.switchToHttp()
    const response = ctx.getResponse<Response>()
    const request = ctx.getRequest<Request>()

    let status = HttpStatus.INTERNAL_SERVER_ERROR
    let message = 'Internal server error'
    let details: any = undefined

    // Handle custom ApiError
    if (exception instanceof ApiError) {
      status = exception.statusCode
      message = exception.message
      details = exception.details

      // Log non-operational errors
      if (!exception.isOperational) {
        console.error('Non-operational error:', {
          message: exception.message,
          stack: exception.stack,
          path: request.url,
          method: request.method
        })
      }
    }
    // Handle NestJS HttpException
    else if (exception instanceof HttpException) {
      status = exception.getStatus()
      const exceptionResponse = exception.getResponse()

      if (typeof exceptionResponse === 'string') {
        message = exceptionResponse
      } else if (typeof exceptionResponse === 'object') {
        message = (exceptionResponse as any).message || message
        details = (exceptionResponse as any).details
      }
    }
    // Handle Zod validation errors
    else if (exception instanceof ZodError) {
      status = HttpStatus.BAD_REQUEST
      message = 'Validation failed'
      details = exception.errors.map(err => ({
        field: err.path.join('.'),
        message: err.message
      }))
    }
    // Handle unknown errors
    else if (exception instanceof Error) {
      message = exception.message

      // Log unexpected errors
      console.error('Unexpected error:', {
        message: exception.message,
        stack: exception.stack,
        path: request.url,
        method: request.method
      })
    }

    // Send error response
    response.status(status).json({
      success: false,
      error: {
        message,
        statusCode: status,
        timestamp: new Date().toISOString(),
        path: request.url,
        ...(details && { details })
      }
    })
  }
}

import { Injectable, NestMiddleware } from '@nestjs/common'
import { Request, Response, NextFunction } from 'express'
import Redis from 'ioredis'
import { RateLimitError } from '../errors/api-error'

/**
 * Rate limiting configuration
 */
interface RateLimitConfig {
  windowMs: number      // Time window in milliseconds
  maxRequests: number   // Maximum requests per window
  keyPrefix?: string    // Redis key prefix
}

/**
 * Rate Limiter Middleware
 * Implements rate limiting using Redis
 * Following Universal Brain backend-patterns rate limiting pattern
 */
@Injectable()
export class RateLimiterMiddleware implements NestMiddleware {
  private config: RateLimitConfig

  constructor(
    private redis: Redis,
    config?: Partial<RateLimitConfig>
  ) {
    this.config = {
      windowMs: config?.windowMs || 60000,        // Default: 1 minute
      maxRequests: config?.maxRequests || 100,    // Default: 100 requests
      keyPrefix: config?.keyPrefix || 'rate-limit'
    }
  }

  async use(req: Request, res: Response, next: NextFunction) {
    try {
      // Get identifier (IP address or user ID)
      const identifier = this.getIdentifier(req)
      const key = `${this.config.keyPrefix}:${identifier}`

      // Increment request count
      const requests = await this.redis.incr(key)

      // Set expiry on first request
      if (requests === 1) {
        await this.redis.pexpire(key, this.config.windowMs)
      }

      // Get TTL for rate limit reset time
      const ttl = await this.redis.pttl(key)

      // Set rate limit headers
      res.setHeader('X-RateLimit-Limit', this.config.maxRequests)
      res.setHeader('X-RateLimit-Remaining', Math.max(0, this.config.maxRequests - requests))
      res.setHeader('X-RateLimit-Reset', new Date(Date.now() + ttl).toISOString())

      // Check if rate limit exceeded
      if (requests > this.config.maxRequests) {
        throw new RateLimitError(
          `Rate limit exceeded. Try again in ${Math.ceil(ttl / 1000)} seconds`
        )
      }

      next()
    } catch (error) {
      if (error instanceof RateLimitError) {
        throw error
      }

      // Log Redis errors but don't block requests
      console.error('Rate limiter error:', error)
      next()
    }
  }

  /**
   * Get identifier for rate limiting
   * Uses user ID if authenticated, otherwise IP address
   */
  private getIdentifier(req: Request): string {
    // Check for authenticated user
    const user = (req as any).user
    if (user?.id) {
      return `user:${user.id}`
    }

    // Fall back to IP address
    const ip = req.ip || 
               req.headers['x-forwarded-for'] as string ||
               req.headers['x-real-ip'] as string ||
               req.socket.remoteAddress ||
               'unknown'

    return `ip:${ip}`
  }
}

/**
 * Factory function to create rate limiter with custom config
 */
export function createRateLimiter(
  redis: Redis,
  config?: Partial<RateLimitConfig>
): RateLimiterMiddleware {
  return new RateLimiterMiddleware(redis, config)
}

import { PrismaClient, MarketplaceListing, ListingStatus, ItemCategory, ItemRarity } from '@prisma/client'
import { BaseRepository, PaginatedResponse, PaginationOptions } from './base.repository'

/**
 * Marketplace listing with seller information
 */
export interface ListingWithSeller extends MarketplaceListing {
  seller: {
    id: string
    username: string
    email: string
  }
}

/**
 * Create listing DTO
 */
export interface CreateListingDto {
  sellerId: string
  itemId: string
  itemName: string
  itemCategory: ItemCategory
  itemRarity: ItemRarity
  quantity: number
  price: bigint
  listingType: 'FIXED_PRICE' | 'AUCTION'
  minBidIncrement?: bigint
  expiresAt: Date
}

/**
 * Update listing DTO
 */
export interface UpdateListingDto {
  price?: bigint
  quantity?: number
  status?: ListingStatus
  expiresAt?: Date
}

/**
 * Listing filter options
 */
export interface ListingFilters {
  sellerId?: string
  status?: ListingStatus
  itemCategory?: ItemCategory
  itemRarity?: ItemRarity
  minPrice?: bigint
  maxPrice?: bigint
  search?: string
}

/**
 * Marketplace Repository Interface
 */
export interface MarketplaceRepository extends BaseRepository<MarketplaceListing, CreateListingDto, UpdateListingDto> {
  findByIdWithSeller(id: string): Promise<ListingWithSeller | null>
  findAllWithSellers(filters?: ListingFilters): Promise<ListingWithSeller[]>
  findAllPaginated(filters?: ListingFilters, options?: PaginationOptions): Promise<PaginatedResponse<ListingWithSeller>>
  findBySeller(sellerId: string): Promise<MarketplaceListing[]>
  findExpired(): Promise<MarketplaceListing[]>
  updateStatus(id: string, status: ListingStatus): Promise<MarketplaceListing>
}

/**
 * Prisma implementation of Marketplace Repository
 * Demonstrates N+1 query prevention from Universal Brain backend-patterns
 */
export class PrismaMarketplaceRepository implements MarketplaceRepository {
  constructor(private prisma: PrismaClient) {}

  /**
   * Find all listings WITHOUT sellers (basic query)
   */
  async findAll(filters?: ListingFilters): Promise<MarketplaceListing[]> {
    const where = this.buildWhereClause(filters)

    return this.prisma.marketplaceListing.findMany({
      where,
      orderBy: { createdAt: 'desc' }
    })
  }

  /**
   * Find all listings WITH sellers (optimized - prevents N+1)
   * GOOD: Uses Prisma include to fetch sellers in single query
   */
  async findAllWithSellers(filters?: ListingFilters): Promise<ListingWithSeller[]> {
    const where = this.buildWhereClause(filters)

    return this.prisma.marketplaceListing.findMany({
      where,
      include: {
        seller: {
          select: {
            id: true,
            username: true,
            email: true
          }
        }
      },
      orderBy: { createdAt: 'desc' }
    }) as Promise<ListingWithSeller[]>
  }

  /**
   * Find paginated listings with sellers (optimized)
   */
  async findAllPaginated(
    filters?: ListingFilters,
    options?: PaginationOptions
  ): Promise<PaginatedResponse<ListingWithSeller>> {
    const page = options?.page || 1
    const limit = options?.limit || 20
    const skip = (page - 1) * limit

    const where = this.buildWhereClause(filters)

    const [data, total] = await Promise.all([
      this.prisma.marketplaceListing.findMany({
        where,
        skip,
        take: limit,
        include: {
          seller: {
            select: {
              id: true,
              username: true,
              email: true
            }
          }
        },
        orderBy: options?.sortBy
          ? { [options.sortBy]: options.sortOrder || 'desc' }
          : { createdAt: 'desc' }
      }),
      this.prisma.marketplaceListing.count({ where })
    ])

    return {
      data: data as ListingWithSeller[],
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit)
      }
    }
  }

  async findById(id: string): Promise<MarketplaceListing | null> {
    return this.prisma.marketplaceListing.findUnique({
      where: { id }
    })
  }

  async findByIdWithSeller(id: string): Promise<ListingWithSeller | null> {
    return this.prisma.marketplaceListing.findUnique({
      where: { id },
      include: {
        seller: {
          select: {
            id: true,
            username: true,
            email: true
          }
        }
      }
    }) as Promise<ListingWithSeller | null>
  }

  async findBySeller(sellerId: string): Promise<MarketplaceListing[]> {
    return this.prisma.marketplaceListing.findMany({
      where: { sellerId },
      orderBy: { createdAt: 'desc' }
    })
  }

  async findExpired(): Promise<MarketplaceListing[]> {
    return this.prisma.marketplaceListing.findMany({
      where: {
        status: 'ACTIVE',
        expiresAt: {
          lt: new Date()
        }
      }
    })
  }

  async create(data: CreateListingDto): Promise<MarketplaceListing> {
    return this.prisma.marketplaceListing.create({
      data: {
        sellerId: data.sellerId,
        itemId: data.itemId,
        itemName: data.itemName,
        itemCategory: data.itemCategory,
        itemRarity: data.itemRarity,
        quantity: data.quantity,
        price: data.price,
        listingType: data.listingType,
        minBidIncrement: data.minBidIncrement,
        expiresAt: data.expiresAt,
        status: 'ACTIVE'
      }
    })
  }

  async update(id: string, data: UpdateListingDto): Promise<MarketplaceListing> {
    return this.prisma.marketplaceListing.update({
      where: { id },
      data
    })
  }

  async updateStatus(id: string, status: ListingStatus): Promise<MarketplaceListing> {
    return this.prisma.marketplaceListing.update({
      where: { id },
      data: { status }
    })
  }

  async delete(id: string): Promise<void> {
    await this.prisma.marketplaceListing.update({
      where: { id },
      data: { deletedAt: new Date() }
    })
  }

  /**
   * Build where clause from filters
   */
  private buildWhereClause(filters?: ListingFilters): any {
    const where: any = {}

    if (filters?.sellerId) {
      where.sellerId = filters.sellerId
    }

    if (filters?.status) {
      where.status = filters.status
    }

    if (filters?.itemCategory) {
      where.itemCategory = filters.itemCategory
    }

    if (filters?.itemRarity) {
      where.itemRarity = filters.itemRarity
    }

    if (filters?.minPrice || filters?.maxPrice) {
      where.price = {}
      if (filters.minPrice) {
        where.price.gte = filters.minPrice
      }
      if (filters.maxPrice) {
        where.price.lte = filters.maxPrice
      }
    }

    if (filters?.search) {
      where.itemName = {
        contains: filters.search,
        mode: 'insensitive'
      }
    }

    return where
  }
}

import Redis from 'ioredis'

/**
 * Cacheable decorator for method-level caching
 * Following Universal Brain backend-patterns caching strategy
 * 
 * @param ttl Time to live in seconds (default: 300 = 5 minutes)
 * @param keyPrefix Optional key prefix for cache keys
 */
export function Cacheable(ttl: number = 300, keyPrefix?: string) {
  return function (
    target: any,
    propertyKey: string,
    descriptor: PropertyDescriptor
  ) {
    const originalMethod = descriptor.value

    descriptor.value = async function (...args: any[]) {
      // Get Redis instance from class
      const redis: Redis = (this as any).redis

      if (!redis) {
        console.warn('Redis not available, skipping cache')
        return originalMethod.apply(this, args)
      }

      // Generate cache key
      const prefix = keyPrefix || target.constructor.name
      const argsKey = JSON.stringify(args)
      const cacheKey = `${prefix}:${propertyKey}:${argsKey}`

      try {
        // Check cache
        const cached = await redis.get(cacheKey)

        if (cached) {
          return JSON.parse(cached)
        }

        // Cache miss - execute method
        const result = await originalMethod.apply(this, args)

        // Cache result
        if (result !== null && result !== undefined) {
          await redis.setex(cacheKey, ttl, JSON.stringify(result))
        }

        return result
      } catch (error) {
        console.error('Cache error:', error)
        // Fall back to executing method without cache
        return originalMethod.apply(this, args)
      }
    }

    return descriptor
  }
}

/**
 * Cache invalidation decorator
 * Invalidates cache entries matching the pattern
 * 
 * @param pattern Pattern to match cache keys (supports wildcards)
 */
export function InvalidateCache(pattern: string) {
  return function (
    target: any,
    propertyKey: string,
    descriptor: PropertyDescriptor
  ) {
    const originalMethod = descriptor.value

    descriptor.value = async function (...args: any[]) {
      // Execute method first
      const result = await originalMethod.apply(this, args)

      // Get Redis instance
      const redis: Redis = (this as any).redis

      if (redis) {
        try {
          // Find and delete matching keys
          const keys = await redis.keys(pattern)

          if (keys.length > 0) {
            await redis.del(...keys)
          }
        } catch (error) {
          console.error('Cache invalidation error:', error)
        }
      }

      return result
    }

    return descriptor
  }
}

/**
 * Cache manager utility class
 */
export class CacheManager {
  constructor(private redis: Redis) {}

  /**
   * Get cached value
   */
  async get<T>(key: string): Promise<T | null> {
    try {
      const cached = await this.redis.get(key)
      return cached ? JSON.parse(cached) : null
    } catch (error) {
      console.error('Cache get error:', error)
      return null
    }
  }

  /**
   * Set cached value
   */
  async set(key: string, value: any, ttl: number = 300): Promise<void> {
    try {
      await this.redis.setex(key, ttl, JSON.stringify(value))
    } catch (error) {
      console.error('Cache set error:', error)
    }
  }

  /**
   * Delete cached value
   */
  async delete(key: string): Promise<void> {
    try {
      await this.redis.del(key)
    } catch (error) {
      console.error('Cache delete error:', error)
    }
  }

  /**
   * Delete multiple keys matching pattern
   */
  async deletePattern(pattern: string): Promise<void> {
    try {
      const keys = await this.redis.keys(pattern)
      if (keys.length > 0) {
        await this.redis.del(...keys)
      }
    } catch (error) {
      console.error('Cache delete pattern error:', error)
    }
  }

  /**
   * Clear all cache
   */
  async clear(): Promise<void> {
