/**
 * Marketplace Service
 * Demonstrates Repository Pattern + Caching from Universal Brain
 */
@Injectable()
export class MarketplaceService {
  private marketplaceRepo: MarketplaceRepository

  constructor(
    private prisma: PrismaClient,
    private redis: Redis
  ) {
    this.marketplaceRepo = new PrismaMarketplaceRepository(prisma)
  }

  /**
   * Get all listings with pagination and caching
   * Cache for 5 minutes (300 seconds)
   */
  @Cacheable(300, 'marketplace')
  async getListings(filters?: ListingFilters, options?: PaginationOptions) {
    return this.marketplaceRepo.findAllPaginated(filters, options)
  }

  /**
   * Get single listing by ID with caching
   * Cache for 5 minutes
   */
  @Cacheable(300, 'marketplace')
  async getListingById(id: string) {
    const listing = await this.marketplaceRepo.findByIdWithSeller(id)

    if (!listing) {
      throw new NotFoundError('Listing')
    }

    return listing
  }

  /**
   * Get listings by seller
   * Cache for 2 minutes (120 seconds)
   */
  @Cacheable(120, 'marketplace')
  async getListingsBySeller(sellerId: string) {
    return this.marketplaceRepo.findBySeller(sellerId)
  }

  /**
   * Create new listing
   * Invalidates cache after creation
   */
  @InvalidateCache('marketplace:*')
  async createListing(data: CreateListingDto) {
    // Validate expiry date
    if (data.expiresAt <= new Date()) {
      throw new BadRequestError('Expiry date must be in the future')
    }

    // Validate auction settings
    if (data.listingType === 'AUCTION' && !data.minBidIncrement) {
      throw new BadRequestError('Auction listings require minimum bid increment')
    }

    return this.marketplaceRepo.create(data)
  }

  /**
   * Update listing
   * Invalidates cache after update
   */
  @InvalidateCache('marketplace:*')
  async updateListing(id: string, data: UpdateListingDto) {
    // Check if listing exists
    const existing = await this.marketplaceRepo.findById(id)

    if (!existing) {
      throw new NotFoundError('Listing')
    }

    // Validate status transition
    if (data.status && !this.isValidStatusTransition(existing.status, data.status)) {
      throw new BadRequestError(`Cannot transition from ${existing.status} to ${data.status}`)
    }

    return this.marketplaceRepo.update(id, data)
  }

  /**
   * Delete listing (soft delete)
   * Invalidates cache after deletion
   */
  @InvalidateCache('marketplace:*')
  async deleteListing(id: string) {
    const existing = await this.marketplaceRepo.findById(id)

    if (!existing) {
      throw new NotFoundError('Listing')
    }

    await this.marketplaceRepo.delete(id)
  }

  /**
   * Purchase listing
   * Invalidates cache after purchase
   */
  @InvalidateCache('marketplace:*')
  async purchaseListing(listingId: string, buyerId: string) {
    const listing = await this.marketplaceRepo.findById(listingId)

    if (!listing) {
      throw new NotFoundError('Listing')
    }

    if (listing.status !== 'ACTIVE') {
      throw new BadRequestError('Listing is not available for purchase')
    }

    if (listing.expiresAt < new Date()) {
      throw new BadRequestError('Listing has expired')
    }

    // Update listing status to SOLD
    await this.marketplaceRepo.updateStatus(listingId, 'SOLD')

    // TODO: Create transaction record
    // TODO: Transfer item to buyer
    // TODO: Transfer gold to seller

    return { success: true, message: 'Purchase successful' }
  }

  /**
   * Expire old listings (background job)
   * Invalidates cache after expiring listings
   */
  @InvalidateCache('marketplace:*')
  async expireOldListings() {
    const expiredListings = await this.marketplaceRepo.findExpired()

    for (const listing of expiredListings) {
      await this.marketplaceRepo.updateStatus(listing.id, 'EXPIRED')
    }

    return {
      expired: expiredListings.length,
      message: `Expired ${expiredListings.length} listings`
    }
  }

  /**
   * Validate status transition
   */
  private isValidStatusTransition(from: string, to: string): boolean {
    const validTransitions: Record<string, string[]> = {
      ACTIVE: ['SOLD', 'EXPIRED', 'CANCELLED'],
      SOLD: [],
      EXPIRED: [],
      CANCELLED: []
    }

    return validTransitions[from]?.includes(to) || false
  }
}

