async getProfile(userId: string) {
  const user = await this.prisma.user.findUnique({
    where: { id: userId, deletedAt: null },
    select: {
      id: true,
      email: true,
      username: true,
      role: true,
      isVerified: true,
      premiumTier: true,
      premiumExpiry: true,
      goldBalance: true,
      lastLoginAt: true,
      createdAt: true,
      updatedAt: true,
      discordId: true,
      googleId: true,
    },
  });

  if (!user) {
    throw new NotFoundException('User not found');
  }

  return {
    ...user,
    goldBalance: user.goldBalance.toString(),
    hasDiscordLinked: !!user.discordId,
    hasGoogleLinked: !!user.googleId,
    discordId: undefined,
    googleId: undefined,
  };
}

