/**
 * Update the current user's profile.
 * Validates uniqueness of username/email if changed.
 * Invalidates cache after update.
 */
@InvalidateCache('user-profile:*')
async updateProfile(userId: string, dto: UpdateProfileDto) {
  // Check for conflicts if username or email is being changed
  if (dto.username) {
    const existingUser = await this.userRepo.findByUsername(dto.username);
    if (existingUser && existingUser.id !== userId) {
      throw new ConflictError('Username already taken');
    }
  }

  if (dto.email) {
    const existingUser = await this.userRepo.findByEmail(dto.email);
    if (existingUser && existingUser.id !== userId) {
      throw new ConflictError('Email already registered');
    }
  }

  // Update user profile
  const updatedUser = await this.userRepo.update(userId, {
    ...(dto.username && { username: dto.username }),
    ...(dto.email && { email: dto.email, isVerified: false }),
  });

  this.logger.log(`Profile updated for user: ${userId}`);

  return {
    id: updatedUser.id,
    email: updatedUser.email,
    username: updatedUser.username,
    role: updatedUser.role,
    isVerified: updatedUser.isVerified,
    premiumTier: updatedUser.premiumTier,
    premiumExpiry: updatedUser.premiumExpiry,
    goldBalance: updatedUser.goldBalance.toString(),
    lastLoginAt: updatedUser.lastLoginAt,
    createdAt: updatedUser.createdAt,
    updatedAt: updatedUser.updatedAt,
  };
}

