## Testing Recommendations

### Unit Tests

```typescript
describe('UsersService', () => {
  let service: UsersService
  let userRepo: jest.Mocked<UserRepository>
  let redis: jest.Mocked<Redis>

  beforeEach(() => {
    userRepo = {
      findById: jest.fn(),
      findByEmail: jest.fn(),
      findByUsername: jest.fn(),
      update: jest.fn(),
    } as any

    redis = {
      get: jest.fn(),
      setex: jest.fn(),
      del: jest.fn(),
    } as any

    service = new UsersService(prisma, redis)
    service['userRepo'] = userRepo
  })

  describe('getProfile', () => {
    it('should return cached profile if available', async () => {
      const cachedUser = { id: '1', username: 'test' }
      redis.get.mockResolvedValue(JSON.stringify(cachedUser))

      const result = await service.getProfile('1')

      expect(redis.get).toHaveBeenCalled()
      expect(userRepo.findById).not.toHaveBeenCalled()
    })

    it('should fetch from database if cache miss', async () => {
      redis.get.mockResolvedValue(null)
      userRepo.findById.mockResolvedValue({ id: '1', username: 'test' } as any)

      const result = await service.getProfile('1')

      expect(userRepo.findById).toHaveBeenCalledWith('1')
      expect(redis.setex).toHaveBeenCalled()
    })

    it('should throw NotFoundError if user not found', async () => {
      redis.get.mockResolvedValue(null)
      userRepo.findById.mockResolvedValue(null)

      await expect(service.getProfile('1')).rejects.toThrow(NotFoundError)
    })
  })

  describe('updateProfile', () => {
    it('should invalidate cache after update', async () => {
      userRepo.findByUsername.mockResolvedValue(null)
      userRepo.update.mockResolvedValue({ id: '1', username: 'newname' } as any)

      await service.updateProfile('1', { username: 'newname' })

      expect(redis.del).toHaveBeenCalled()
    })

    it('should throw ConflictError if username taken', async () => {
      userRepo.findByUsername.mockResolvedValue({ id: '2', username: 'taken' } as any)

      await expect(
        service.updateProfile('1', { username: 'taken' })
      ).rejects.toThrow(ConflictError)
    })
  })
})
```

